// Extract Wazuh alert data
const body = $input.item.json.body || $input.item.json;

// Determine severity based on Wazuh rule level
let severity = 'low';
const level = body.rule?.level || 0;

if (level >= 12) {
  severity = 'critical';
} else if (level >= 7) {
  severity = 'high';
} else if (level >= 4) {
  severity = 'medium';
}

// Create structured alert object WITH data field preserved
const alert = {
  id: body.id || Date.now().toString(),
  timestamp: body.timestamp || new Date().toISOString(),
  rule: {
    description: body.rule?.description || 'Security alert detected',
    level: level,
    id: body.rule?.id || 'unknown'
  },
  agent: {
    name: body.agent?.name || 'Unknown Agent',
    id: body.agent?.id || 'unknown'
  },
  data: body.data || {},  // ← PRESERVE data field
  full_log: body.full_log || '',  // ← PRESERVE full_log field
  severity: severity,
  description: body.rule?.description || 'Security alert detected'
};

return { json: { alert } };

