// Get the alert from Process Alert node
const alert = $('Process Alert').item.json.alert;

// Get AI response
const aiResponse = $input.item.json.response || 'AI analysis unavailable';

// Combine alert with AI analysis
const enrichedAlert = {
  id: alert.id,
  timestamp: alert.timestamp,
  rule: alert.rule,
  agent: alert.agent,
  severity: alert.severity,
  description: alert.description,
  ai_analysis: aiResponse,
  processed_at: new Date().toISOString()
};

return { json: enrichedAlert };

// Parse AI response and make decision
const alertData = $('Merge').item.json;
const rawResponse = $input.item.json.ai_analysis || '{}';

let aiDecision;
try {
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  aiDecision = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  aiDecision = {
    severity: alertData.alert?.severity || 'medium',
    confidence: 0.5,
    threat_type: 'unknown',
    action: 'monitor',
    auto_execute: false,
    reasoning: 'Could not parse AI response'
  };
}

const confidence = aiDecision.confidence || 0;
const severity = aiDecision.severity || 'low';

// Decision logic
let shouldExecute = false;
let finalAction = 'monitor';

if (confidence >= 0.90 && (severity === 'critical' || severity === 'high')) {
  shouldExecute = true;
  finalAction = aiDecision.action || 'block_ip';
} else if (confidence >= 0.85 && severity === 'high') {
  shouldExecute = true;
  finalAction = 'rate_limit';
} else if (confidence >= 0.70) {
  shouldExecute = false;
  finalAction = 'alert_team';
}

return {
  json: {
    ...alertData,
    ai_severity: aiDecision.severity,
    ai_confidence: confidence,
    ai_threat_type: aiDecision.threat_type || 'unknown',
    ai_action: finalAction,
    ai_auto_execute: shouldExecute,
    ai_reasoning: aiDecision.reasoning || 'No reasoning',
    sourceIP: alertData.sourceIP || 'unknown'
  }
};

const d = $input.item.json;

