const allInputs = $input.all();
const ollamaData = allInputs[0]?.json || {};

// Get raw response and strip DeepSeek thinking
let rawResponse = ollamaData.response || '';
rawResponse = rawResponse.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

// Parse AI JSON
let aiData = {};
try {
  const match = rawResponse.match(/\{[\s\S]*\}/);
  if (match) aiData = JSON.parse(match[0]);
} catch(e) {
  aiData = { threat_level: 'medium', confidence: 0.5, attack_type: 'unknown', action: 'monitor', reason: 'parse error', analysis: '' };
}

let confidence = parseFloat(aiData.confidence) || 0.5;
if (confidence > 1.0) confidence = confidence / 100.0;

// Get alert data from previous nodes using $('node name')
let alertData = {};
try {
  alertData = $('Extract IP Address').first().json || {};
} catch(e) {
  alertData = {};
}

const agentName = alertData.agent?.name || alertData.alert?.agent?.name || 'unknown';
const severity = alertData.severity || alertData.alert?.severity || 'unknown';
const sourceIP = alertData.sourceIP || 'unknown';
const ruleLevel = alertData.alert?.rule?.level || alertData.rule?.level || 0;
const description = alertData.alert?.rule?.description || alertData.rule?.description || '';

return {
  json: {
    id: alertData.alert?.id || alertData.id,
    timestamp: alertData.alert?.timestamp || alertData.timestamp,
    rule: alertData.alert?.rule || alertData.rule,
    agent: { name: agentName },
    severity: severity,
    description: description,
    sourceIP: sourceIP,
    isLocalhost: alertData.isLocalhost || false,
    ai_threat_level: aiData.threat_level || 'medium',
    ai_confidence: confidence,
    ai_attack_type: (aiData.attack_type || 'unknown').replace(/ /g, '_'),
    ai_action: aiData.action || 'monitor',
    ai_reason: aiData.reason || '',
    ai_analysis: aiData.analysis || '',
    processed_at: new Date().toISOString()
  }
};

// AI Decision Engine - Confidence-based routing
const data = $input.item.json;
const confidence = data.ai_confidence || 0;
const severity = data.ai_threat_level || data.severity || 'low';
const action = data.ai_action || 'monitor';
const sourceIP = data.sourceIP || 'unknown';

let decision = 'monitor';
let shouldAutoExecute = false;
let executionReason = '';

// Decision logic based on confidence + severity
if (confidence >= 0.95 && (severity === 'critical' || severity === 'high')) {
  shouldAutoExecute = true;
  decision = action;
  executionReason = 'Auto-execute: confidence >= 95% + critical/high severity';
} else if (confidence >= 0.85 && severity === 'high') {
  shouldAutoExecute = true;
  decision = action;
  executionReason = 'Auto-execute: confidence >= 85% + high severity';
} else if (confidence >= 0.70) {
  shouldAutoExecute = false;
  decision = 'prepare_response';
  executionReason = 'Human review required: confidence 70-84%';
} else {
  shouldAutoExecute = false;
  decision = 'monitor';
  executionReason = 'Monitor only: confidence below 70%';
}

// Never auto-block localhost or unknown IPs
if (sourceIP === 'unknown' || sourceIP === '127.0.0.1' || sourceIP.startsWith('192.168.')) {
  shouldAutoExecute = false;
  decision = 'monitor';
  executionReason = 'Skipped: internal/unknown IP';
}

return {
  json: {
    ...data,
    decision: decision,
    shouldAutoExecute: shouldAutoExecute,
    executionReason: executionReason
  }
};

