// RULE-LEVEL OVERRIDE — auto-block if Wazuh says rule_level >= 10 (regardless of AI confidence)
if (ruleLevel >= 10) {
  shouldAutoExecute = true;
  decision = (action !== 'monitor') ? action : 'block_ip';
  executionReason = `Auto-block: Wazuh rule level ${ruleLevel} >= 10`;
}
// HIGH CONFIDENCE + HIGH/CRITICAL SEVERITY
else if (confidence >= 0.85 && (severity === 'critical' || severity === 'high')) {
  shouldAutoExecute = true;
  decision = action;
  executionReason = `Auto-execute: ${Math.round(confidence*100)}% confidence + ${severity} severity`;
}
// HIGH CONFIDENCE ALONE
else if (confidence >= 0.85) {
  shouldAutoExecute = true;
  decision = action;
  executionReason = `Auto-execute: ${Math.round(confidence*100)}% confidence`;
}
// MEDIUM CONFIDENCE — flag for investigation, no auto-action
else if (confidence >= 0.70) {
  shouldAutoExecute = false;
  decision = 'investigate';
  executionReason = `Investigate: ${Math.round(confidence*100)}% confidence — awaiting human review`;
}
else {
  decision = 'monitor';
  executionReason = `Monitor only: rule level ${ruleLevel}, confidence ${Math.round(confidence*100)}%`;
}

return { json: { ...data, decision, shouldAutoExecute, executionReason } };

