{"model": "cisco-sec-8b", "messages": [{"role": "system", "content": "You are a SOC Analyst API. Analyze the security alert and respond with JSON only.

JSON fields:
- threat_type: snake_case attack name (e.g. ssh_brute_force, port_scan, malware, ransomware, lateral_movement, data_exfiltration, privilege_escalation, c2_beacon, sql_injection, unknown)
- severity: integer 1-10
- mitre_id: MITRE ATT&CK ID (e.g. T1110, T1046, T1486)
- confidence: float 0.0-1.0
- action: exactly one of: block_ip, isolate_host, investigate, monitor, revoke_access
- reason: one sentence explanation

Escalation guidance:
- First offense (count=0): prefer monitor or investigate
- Repeat offender (count 3-9): prefer investigate or block_ip
- Persistent attacker (count 10+): prefer block_ip
- Ransomware/malware/C2: always isolate_host regardless of count

No markdown, no backticks, no extra text. JSON only."}, {"role": "user", "content": "Alert: {{ $json.alert?.rule?.description || $json.rule?.description || 'Security alert' }}
Rule Level: {{ $json.alert?.rule?.level || $json.rule?.level || 0 }}/15
Rule ID: {{ $json.alert?.rule?.id || $json.rule?.id || 'unknown' }}
Source IP: {{ $json.sourceIP || 'unknown' }}
Agent: {{ $json.agent?.name || 'unknown' }}
Severity: {{ $json.severity || 'unknown' }}
Previous alerts from this IP (last 24h): {{ $json.ip_history_count || 0 }}
Escalation hint: {{ $json.ip_escalation_hint || 'First time seen.' }}"}], "stream": false, "options": {"num_ctx": 2048, "num_predict": 200, "temperature": 0}}

parameters.jsCode:
const allInputs = $input.all();
const ollamaData = allInputs[0]?.json || {};

// cisco-sec-8b uses /api/chat → response is in message.content
let rawResponse = ollamaData.message?.content || ollamaData.response || '';

// Strip any markdown backticks the model occasionally adds
rawResponse = rawResponse.replace(/```json|```/g, '').trim();

// Parse AI JSON
let aiData = {};
try {
  const match = rawResponse.match(/\{[\s\S]*\}/);
  if (match) aiData = JSON.parse(match[0]);
} catch(e) {
  aiData = { threat_type: 'unknown', severity: 5, confidence: 0.5, mitre_id: 'unknown', action: 'monitor', reason: 'parse error' };
}

// Normalize confidence: cisco model returns 0.0-1.0 correctly, but handle 0-100 just in case
let confidence = parseFloat(aiData.confidence) || 0.5;
if (confidence > 1.0) confidence = confidence / 100.0;

// Get alert data directly from Extract IP Address node (bypasses wire issues)
let alertData = {};
try {
  alertData = $('Extract IP Address').first().json || {};
} catch(e) { alertData = {}; }

const agentName   = alertData.agent?.name || alertData.alert?.agent?.name || 'unknown';
const severity    = alertData.severity || alertData.alert?.severity || 'unknown';
const sourceIP    = alertData.sourceIP || 'unknown';
const ruleLevel   = alertData.alert?.rule?.level || alertData.rule?.level || 0;
const description = alertData.alert?.rule?.description || alertData.rule?.description || '';
const alertId     = alertData.alert?.id || alertData.id;
const timestamp   = alertData.alert?.timestamp || alertData.timestamp;
const rule        = alertData.alert?.rule || alertData.rule;

// cisco-sec-8b fields: threat_type, severity, mitre_id, confidence, action, reason
const threatType = (aiData.threat_type || 'unknown').toLowerCase().replace(/[\s]+/g, '_');
const mitreId    = aiData.mitre_id || 'unknown';
const aiAction   = aiData.action || 'monitor';
const aiReason   = aiData.reason || '';
const aiSeverity = Math.min(10, Math.max(1, parseInt(aiData.severity) || 5));

return {
  json: {
    id: alertId,
    timestamp: timestamp,
    rule: rule,
    agent: { name: agentName },
    severity: severity,
    description: description,
    sourceIP: sourceIP,
    isLocalhost: alertData.isLocalhost || false,
    // cisco-sec-8b field names (not deepseek names)
    ai_threat_type: threatType,
    ai_severity: aiSeverity,
    ai_mitre_id: mitreId,
    ai_confidence: confidence,
    ai_action: aiAction,
    ai_reason: aiReason,
    processed_at: new Date().toISOString()
  }
};

const data = $input.item.json;
const confidence = data.ai_confidence || 0;
const severity   = data.severity || 'low';        // Wazuh severity: critical/high/medium/low
const action     = data.ai_action || 'monitor';
const sourceIP   = data.sourceIP || 'unknown';
const ruleLevel  = data.rule?.level || 0;

let decision = 'monitor';
let shouldAutoExecute = false;
let executionReason = '';

// Skip internal/unknown IPs
if (data.isLocalhost || sourceIP === 'unknown') {
  return { json: { ...data, decision: 'monitor', shouldAutoExecute: false,
    executionReason: 'Skipped: internal/unknown IP' }};
}

// NEVER auto-execute insider threats — always human review required
if (action === 'revoke_access') {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: false,
    executionReason: 'Insider threat — human review required, no auto-action' }};
}

// RULE-LEVEL OVERRIDE — auto-block if Wazuh says rule_level >= 10 (regardless of AI confidence)
if (ruleLevel >= 10) {
  shouldAutoExecute = true;
  decision = (action !== 'monitor') ? action : 'block_ip';
  executionReason = `Auto-block: Wazuh rule level ${ruleLevel} >= 10`;
}
// HIGH CONFIDENCE + HIGH/CRITICAL SEVERITY
else if (confidence >= 0.85 && (severity === 'critical' || severity === 'high')) {
  shouldAutoExecute = true;
  decision = action;
  executionReason = `Auto-execute: ${Math.round(confidence*100)}% confidence + ${severity} severity`;
}
// HIGH CONFIDENCE ALONE
else if (confidence >= 0.85) {
  shouldAutoExecute = true;
  decision = action;
  executionReason = `Auto-execute: ${Math.round(confidence*100)}% confidence`;
}
// MEDIUM CONFIDENCE — flag for investigation, no auto-action
else if (confidence >= 0.70) {
  shouldAutoExecute = false;
  decision = 'investigate';
  executionReason = `Investigate: ${Math.round(confidence*100)}% confidence — awaiting human review`;
}
else {
  decision = 'monitor';
  executionReason = `Monitor only: rule level ${ruleLevel}, confidence ${Math.round(confidence*100)}%`;
}

return { json: { ...data, decision, shouldAutoExecute, executionReason } };

