// Log the action decision to InfluxDB actions measurement
const data = $input.item.json;

const cleanTag = (v) => String(v || 'unknown')
  .replace(/[,=\s"\\]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .substring(0, 80) || 'unknown';

const actionTaken = cleanTag(data.decision || 'monitor');
const sourceIP    = cleanTag(data.sourceIP || 'unknown');   // sanitized — prevents line protocol corruption
const agentName   = cleanTag(data.agent?.name || 'unknown');
const mitreId     = cleanTag(data.ai_mitre_id || 'unknown');
const timestamp   = Math.floor(Date.now() / 1000);
const autoExec    = (data.shouldAutoExecute === true) ? 1 : 0;
const confidence  = parseFloat(data.ai_confidence) || 0;

// Line protocol for actions measurement (separate from alerts measurement)
const lineProtocol = `alerts,host=wazuh,severity=action_log,agent=${agentName},attack_type=action_executed,decision=${actionTaken},source_ip=${sourceIP},mitre_id=${mitreId} rule_level=0,confidence=${confidence},ai_severity=0,auto_execute=${autoExec},reason="action_executed"`;

return {
  json: {
    ...data,
    action_logged: true,
    action_taken: actionTaken,
    lineProtocol: lineProtocol
  }
};

return { 
  json: { 
    success: true, 
    message: 'Alert processed and stored in InfluxDB',
    alert: $input.item.json,
    influxdb_written: true
  } 
};

