        </div>
    </div>
    <script>
        function loadAlerts() {
            fetch('/webhook/get-alerts')
                .then(r => r.json())
                .then(data => { displayAlerts(data.alerts || []); updateStats(data.alerts || []); })
                .catch(() => { document.getElementById('alerts-list').innerHTML = '<div class="no-alerts">Error loading alerts.</div>'; });
        }
        function displayAlerts(alerts) {
            const c = document.getElementById('alerts-list');
            if (!alerts.length) { c.innerHTML = '<div class="no-alerts">No alerts yet. Waiting for Wazuh events...</div>'; return; }
            c.innerHTML = alerts.map(a => {
                const action = a.ai_action || a.decision || 'monitor';
                return '<div class="alert ' + a.severity + '">' +
                    '<div class="alert-header"><div class="alert-title">' + (a.description || 'Security Alert') + '<span class="action-badge ' + action + '">⚡ ' + action.replace('_',' ') + '</span></div>' +
                    '<span class="severity-badge ' + a.severity + '">' + a.severity + '</span></div>' +
                    '<div class="alert-meta"><span>🕐 ' + formatTime(a.timestamp) + '</span><span>🖥️ ' + (a.agent?.name || 'Unknown') + '</span><span>📊 Level: ' + (a.rule?.level || 'N/A') + '</span><span>🌐 IP: ' + (a.sourceIP || 'N/A') + '</span><span>🎯 Confidence: ' + Math.round((a.ai_confidence || 0) * 100) + '%</span></div>' +
                    (a.ai_analysis ? '<div class="ai-analysis"><span class="ai-label">🤖 AI Analysis:</span>' + a.ai_analysis + (a.ai_reason ? '<br><strong>Action Reason:</strong> ' + a.ai_reason : '') + '</div>' : '') +
                '</div>';
            }).join('');
        }
        function updateStats(alerts) {
            document.getElementById('total-alerts').textContent = alerts.length;
            document.getElementById('critical-count').textContent = alerts.filter(a => a.severity === 'critical').length;
            document.getElementById('high-count').textContent = alerts.filter(a => a.severity === 'high').length;
            document.getElementById('blocked-count').textContent = alerts.filter(a => a.decision === 'block_ip' || a.ai_action === 'block_ip').length;
            document.getElementById('last-update').textContent = new Date().toLocaleTimeString();
        }
        function formatTime(t) {
            const d = new Date(t), n = new Date(), diff = Math.floor((n-d)/60000);
            if (diff < 1) return 'Just now'; if (diff < 60) return diff + 'm ago';
            if (diff < 1440) return Math.floor(diff/60) + 'h ago'; return d.toLocaleString();
        }
        loadAlerts();
        setInterval(loadAlerts, 5000);
    </script>
</body>
