        </header>
        <div class="stats">
            <div class="stat-card"><div class="stat-label">Total Alerts</div><div class="stat-value" id="total-alerts">0</div></div>
            <div class="stat-card"><div class="stat-label">Critical</div><div class="stat-value" id="critical-count" style="color:#ef4444">0</div></div>
            <div class="stat-card"><div class="stat-label">High</div><div class="stat-value" id="high-count" style="color:#f97316">0</div></div>
            <div class="stat-card"><div class="stat-label">Auto-Blocked</div><div class="stat-value" id="blocked-count" style="color:#c084fc">0</div></div>
            <div class="stat-card"><div class="stat-label">Last Updated</div><div class="stat-value" id="last-update" style="font-size:16px">--:--</div></div>
