const allInputs = $input.all();
const ollamaData = allInputs[0]?.json || {};

let rawResponse = ollamaData.message?.content || ollamaData.response || '';
rawResponse = rawResponse.replace(/```json|```/g, '').trim();

let aiData = {};
try {
  const match = rawResponse.match(/\{[\s\S]*\}/);
  if (match) aiData = JSON.parse(match[0]);
} catch(e) {
  aiData = { threat_type: 'unknown', severity: 5, confidence: 0.5, mitre_id: 'unknown', action: 'monitor', reason: 'parse error' };
}

let confidence = parseFloat(aiData.confidence) || 0.5;
if (confidence > 1.0) confidence = confidence / 100.0;

// Read enriched data from Parse Last Decision (carries all history fields)
let alertData = {};
try {
  alertData = $('Parse Last Decision').first().json || {};
} catch(e) {
  try { alertData = $('Extract IP Address').first().json || {}; } catch(e2) { alertData = {}; }
}

const agentName   = alertData.agent?.name || alertData.alert?.agent?.name || 'unknown';
const severity    = alertData.severity || alertData.alert?.severity || 'unknown';
const sourceIP    = alertData.sourceIP || 'unknown';
const ruleLevel   = alertData.alert?.rule?.level || alertData.rule?.level || 0;
const description = alertData.alert?.rule?.description || alertData.rule?.description || '';
const alertId     = alertData.alert?.id || alertData.id;
const timestamp   = alertData.alert?.timestamp || alertData.timestamp;
const rule        = alertData.alert?.rule || alertData.rule;

const threatType = (aiData.threat_type || 'unknown').toLowerCase().replace(/[\s]+/g, '_');
const mitreId    = aiData.mitre_id || 'unknown';
const aiAction   = aiData.action || 'monitor';
const aiReason   = aiData.reason || '';
const aiSeverity = Math.min(10, Math.max(1, parseInt(aiData.severity) || 5));

return {
  json: {
    id: alertId,
    timestamp,
    rule,
    agent: { name: agentName, id: alertData.agent?.id || alertData.alert?.agent?.id || '001' },
    severity,
    description,
    sourceIP,
    isLocalhost: alertData.isLocalhost || false,
    ai_threat_type: threatType,
    ai_severity: aiSeverity,
    ai_mitre_id: mitreId,
    ai_confidence: confidence,
    ai_action: aiAction,
    ai_reason: aiReason,
    ip_history_count:   alertData.ip_history_count   || 0,
    ip_velocity_5m:     alertData.ip_velocity_5m     || 0,
    ip_last_decision:   alertData.ip_last_decision   || 'none',
    ip_escalation_hint: alertData.ip_escalation_hint || 'First time seen.',
    processed_at: new Date().toISOString()
  }
};

const data          = $input.item.json;
const confidence    = data.ai_confidence   || 0;
const severity      = data.severity        || 'low';
const action        = data.ai_action       || 'monitor';
const sourceIP      = data.sourceIP        || 'unknown';
const ruleLevel     = data.rule?.level     || 0;
const count24h      = data.ip_history_count || 0;
const velocity5m    = data.ip_velocity_5m  || 0;
const lastDecision  = data.ip_last_decision || 'none';
const threatType    = data.ai_threat_type  || 'unknown';

// ── GUARDS ────────────────────────────────────────────────────────────────
if (data.isLocalhost || sourceIP === 'unknown') {
  return { json: { ...data, decision: 'monitor', shouldAutoExecute: false,
    executionReason: 'Skipped: internal/unknown IP', threat_score: 0 }};
}

if (action === 'revoke_access') {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: false,
    executionReason: 'Insider threat — human review required', threat_score: 0 }};
}

if (['ransomware','malware','c2_beacon'].includes(threatType)) {
  return { json: { ...data, decision: 'isolate_host', shouldAutoExecute: true,
    executionReason: `Critical malware threat: ${threatType} — auto-isolating`, threat_score: 99 }};
}

// ── SCORING MATRIX ────────────────────────────────────────────────────────
let score = 0;

// Base: rule level
score += ruleLevel;

// 5-min velocity (how aggressive right now)
if      (velocity5m >= 15) score += 8;
else if (velocity5m >= 8)  score += 5;
else if (velocity5m >= 3)  score += 3;
else if (velocity5m >= 1)  score += 1;

// 24h history (repeat offender)
if      (count24h >= 20) score += 5;
else if (count24h >= 10) score += 3;
else if (count24h >= 5)  score += 2;
else if (count24h >= 1)  score += 1;

// Escalation (we warned them — they came back)
if      (lastDecision === 'block_ip')    score += 6;
else if (lastDecision === 'investigate') score += 3;
else if (lastDecision === 'monitor')     score += 1;

// AI confidence modifier
if      (confidence >= 0.85) score += 2;
else if (confidence >= 0.70) score += 1;

// ── DECISION FROM SCORE ───────────────────────────────────────────────────
const ctx = `[score=${score} | rule=${ruleLevel} | vel5m=${velocity5m} | 24h=${count24h} | last=${lastDecision} | conf=${Math.round(confidence*100)}%]`;

let decision, shouldAutoExecute, executionReason;

if (score >= 18) {
  decision = 'block_ip';
  shouldAutoExecute = true;
  executionReason = `Auto-block: high threat score ${ctx}`;
}
else if (score >= 13) {
  decision = 'block_ip';
  shouldAutoExecute = true;
  executionReason = `Auto-block: elevated threat score ${ctx}`;
}
else if (score >= 7) {
  decision = 'investigate';
  shouldAutoExecute = false;
  executionReason = `Investigate: moderate threat score ${ctx}`;
}
else {
  decision = 'monitor';
  shouldAutoExecute = false;
  executionReason = `Monitor only: low threat score ${ctx}`;
}

return { json: { ...data, decision, shouldAutoExecute, executionReason, threat_score: score } };

