const cleanTag = (v) => String(v || 'unknown')
  .replace(/[,=\s\"\\]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .substring(0, 80) || 'unknown';

const cleanStr = (v) => String(v || '')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/[\n\r\t]/g, ' ')
  .trim()
  .substring(0, 150);

const actionTaken = cleanTag(data.decision || 'monitor');
