// Parse CSV response from InfluxDB and convert to alerts array
const csvData = $input.item.json.data || $input.item.json.body || '';

let alerts = [];

try {
  const lines = csvData.split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length > 1) {
    const headers = lines[0].split(',');
    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      if (vals.length < 2) continue;
      const obj = {};
      headers.forEach((h, idx) => { obj[h.trim()] = vals[idx]?.trim() || ''; });

      // Build alert object from InfluxDB fields
      if (obj._time || obj.description) {
        alerts.push({
          id: obj._time || Date.now().toString(),
          timestamp: obj._time || new Date().toISOString(),
          severity: obj.severity || 'low',
          description: obj.description || 'Security Alert',
          sourceIP: obj.source_ip || 'unknown',
          ai_analysis: obj.ai_analysis || '',
          ai_confidence: parseFloat(obj.confidence) || 0,
          ai_action: obj.decision || 'monitor',
          decision: obj.decision || 'monitor',
          ai_reason: obj.ai_reason || '',
          rule: { level: parseInt(obj.rule_level) || 0 },
          agent: { name: obj.agent || 'Unknown' }
        });
      }
    }
  }
} catch(e) {
  alerts = [];
}

return { json: { alerts: alerts, count: alerts.length } };

const d = $input.item.json;

// For tag values: strip chars InfluxDB can't handle in tag sets
const cleanTag = (v) => String(v || 'unknown')
  .replace(/[,=\s"\\]+/g, '_')
  .replace(/^_+|_+$/g, '')
  .substring(0, 80) || 'unknown';

// For string field values: escape backslash and quote, preserve spaces
const cleanStr = (v) => String(v || '')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/[\n\r\t]/g, ' ')
  .trim()
  .substring(0, 150);

const num = (v, def=0) => { const n = parseFloat(v); return isNaN(n) ? def : n; };

// Support BOTH data structures:
// 1. From AI Decision Engine (flat): d.agent.name, d.rule.level
// 2. From IF[out1] direct path (nested): d.alert.agent.name, d.alert.rule.level
const severity   = cleanTag(d.severity || d.alert?.severity);
const agent      = cleanTag(d.agent?.name || d.alert?.agent?.name);
const attackType = cleanTag(d.ai_threat_type || 'unanalyzed');
const decision   = cleanTag(d.decision || 'monitor');
const sourceIP   = cleanTag(d.sourceIP);
const mitreId    = cleanTag(d.ai_mitre_id || 'unknown');

const ruleLevel  = num(d.rule?.level || d.alert?.rule?.level, 0);
const confidence = num(d.ai_confidence, 0.0);
const aiSeverity = num(d.ai_severity, 0);
const autoExec   = (d.shouldAutoExecute === true) ? 1 : 0;
const reason     = cleanStr(d.ai_reason || '');

// ONE space between tag set and field set. No second space. All fields comma-separated.
const lineProtocol = `alerts,host=wazuh,severity=${severity},agent=${agent},attack_type=${attackType},decision=${decision},source_ip=${sourceIP},mitre_id=${mitreId} rule_level=${ruleLevel},confidence=${confidence},ai_severity=${aiSeverity},auto_execute=${autoExec},reason="${reason}"`;

return { json: { ...d, lineProtocol } };

// Parse InfluxDB CSV response for IP count and inject into alert data
const responseBody = $input.item.json.body || $input.item.json.data || '';

// ✅ FIX: Use Extract IP Address (has sourceIP) NOT Merge (which returns VT data first)
const alertData = $('Extract IP Address').first().json;

let ipCount = 0;

try {
  // InfluxDB CSV: parse _value column for count
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const valueIdx = headers.findIndex(h => h.trim() === '_value');
    if (valueIdx >= 0 && lines[1]) {
      const vals = lines[1].split(',');
      ipCount = parseInt(vals[valueIdx]) || 0;
    }
  }
} catch(e) {
  ipCount = 0;
}

// Determine escalation hint based on count
let escalationHint = '';
if (ipCount === 0) {
  escalationHint = 'First time seen. Be cautious but fair.';
} else if (ipCount < 3) {
  escalationHint = `Seen ${ipCount} time(s) before. Consider investigate.`;
} else if (ipCount < 10) {
  escalationHint = `Seen ${ipCount} times in 24h. Strong pattern — consider block_ip.`;
} else {
  escalationHint = `Seen ${ipCount} times in 24h. Persistent attacker — recommend block_ip.`;
}

return {
  json: {
    ...alertData,
    ip_history_count: ipCount,
    ip_escalation_hint: escalationHint
  }
};

// Parse InfluxDB CSV response to check if IP was already blocked
const responseBody = $input.item.json.body || $input.item.json.data || '';

let alreadyBlocked = false;
let blockCount = 0;

try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const valueIdx = headers.findIndex(h => h.trim() === '_value');
    if (valueIdx >= 0 && lines[1]) {
      const vals = lines[1].split(',');
      blockCount = parseInt(vals[valueIdx]) || 0;
      alreadyBlocked = blockCount > 0;
    }
  }
} catch(e) {
  // If query fails, assume not blocked — safer to re-block than to skip
  alreadyBlocked = false;
  blockCount = 0;
}

const sourceIP = $('AI Decision Engine').first().json.sourceIP || 'unknown';

return {
  json: {
    ...$('AI Decision Engine').first().json,
    already_blocked: alreadyBlocked,
    block_count_1h: blockCount,
    dedup_note: alreadyBlocked
      ? `IP ${sourceIP} was already blocked ${blockCount} time(s) in last 1h — skipping Wazuh API call`
      : `IP ${sourceIP} not blocked recently — proceeding with block`
  }
};

const responseBody = $input.item.json.body || $input.item.json.data || '';
const prevData = $('Parse IP History').first().json;

let velocity5m = 0;
try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
