    const timeIdx = headers.findIndex(h => h.trim() === '_time');

    // Find the row with the most recent _time (query already sorted desc, so first row is latest)
    // But also scan all rows to find any non-none decision
    let latestTime = '';
    let latestDecision = 'none';

    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      const rowDecision = decisionIdx >= 0 ? (vals[decisionIdx] || '').trim() : '';
      const rowTime = timeIdx >= 0 ? (vals[timeIdx] || '').trim() : '';

      if (rowDecision && rowDecision !== '' && rowDecision !== 'none') {
        // Take first valid row since query is sorted desc (most recent first)
