const responseBody = $input.item.json.body || $input.item.json.data || '';
const prevData = $('Parse 5min Velocity').first().json;

let lastDecision = 'none';

try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const decisionIdx = headers.findIndex(h => h.trim() === 'decision');
    const timeIdx = headers.findIndex(h => h.trim() === '_time');

    // Find the row with the most recent _time (query already sorted desc, so first row is latest)
    // But also scan all rows to find any non-none decision
    let latestTime = '';
    let latestDecision = 'none';

    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      const rowDecision = decisionIdx >= 0 ? (vals[decisionIdx] || '').trim() : '';
      const rowTime = timeIdx >= 0 ? (vals[timeIdx] || '').trim() : '';

      if (rowDecision && rowDecision !== '' && rowDecision !== 'none') {
        // Take first valid row since query is sorted desc (most recent first)
        if (latestDecision === 'none') {
          latestDecision = rowDecision;
          latestTime = rowTime;
        }
      }
    }
    lastDecision = latestDecision;
  }
} catch(e) {
  lastDecision = 'none';
}

return {
  json: {
    ...prevData,
    ip_last_decision: lastDecision
  }
};

