const allInputs = $input.all();
const ollamaData = allInputs[0]?.json || {};

// cisco-sec-8b uses /api/chat → response is in message.content
let rawResponse = ollamaData.message?.content || ollamaData.response || '';

// Strip any markdown backticks the model occasionally adds
rawResponse = rawResponse.replace(/```json|```/g, '').trim();

// Parse AI JSON — fallback if Ollama timed out or failed
let aiData = {};
try {
  const match = rawResponse.match(/\{[\s\S]*\}/);
  if (match) aiData = JSON.parse(match[0]);
} catch(e) {
  aiData = { threat_type: 'unknown', severity: 5, confidence: 0.5, mitre_id: 'unknown', action: 'monitor', reason: 'AI unavailable - using count-based fallback' };
}

// Normalize confidence: handle both 0.0-1.0 and 0-100 formats
let confidence = parseFloat(aiData.confidence) || 0.5;
if (confidence > 1.0) confidence = confidence / 100.0;

// Get full alert data from Parse Last Decision (has ALL context: history, velocity, lastDecision)
let alertData = {};
try {
  alertData = $('Parse Last Decision').first().json || {};
} catch(e) {
  try {
    alertData = $('Extract IP Address').first().json || {};
  } catch(e2) { alertData = {}; }
}

const agentName   = alertData.agent?.name || alertData.alert?.agent?.name || 'unknown';
const severity    = alertData.severity || alertData.alert?.severity || 'unknown';
const sourceIP    = alertData.sourceIP || 'unknown';
const ruleLevel   = alertData.alert?.rule?.level || alertData.rule?.level || 0;
const description = alertData.alert?.rule?.description || alertData.rule?.description || '';
const alertId     = alertData.alert?.id || alertData.id;
const timestamp   = alertData.alert?.timestamp || alertData.timestamp;
const rule        = alertData.alert?.rule || alertData.rule;

// cisco-sec-8b field names
const threatType = (aiData.threat_type || 'unknown').toLowerCase().replace(/[\s]+/g, '_');
const mitreId    = aiData.mitre_id || 'unknown';
const aiAction   = aiData.action || 'monitor';
const aiReason   = aiData.reason || '';
const aiSeverity = Math.min(10, Math.max(1, parseInt(aiData.severity) || 5));

return {
  json: {
    id: alertId,
    timestamp: timestamp,
    rule: rule,
    agent: { name: agentName, id: alertData.agent?.id || alertData.alert?.agent?.id || '001' },
    severity: severity,
    description: description,
    sourceIP: sourceIP,
    isLocalhost: alertData.isLocalhost || false,
    // AI analysis fields
    ai_threat_type: threatType,
    ai_severity: aiSeverity,
    ai_mitre_id: mitreId,
    ai_confidence: confidence,
    ai_action: aiAction,
    ai_reason: aiReason,
    // Memory fields — from the full query chain
    ip_history_count: alertData.ip_history_count || 0,
    ip_velocity_5m: alertData.ip_velocity_5m || 0,
    ip_last_decision: alertData.ip_last_decision || 'none',
    processed_at: new Date().toISOString()
  }
};

const data = $input.item.json;
const sourceIP = data.sourceIP || 'unknown';
const ruleLevel = data.rule?.level || 0;
const aiAction = data.ai_action || 'monitor';
const threatType = (data.ai_threat_type || '').toLowerCase();

// ── SKIP: internal/unknown IPs ──────────────────────────────────────
if (data.isLocalhost || sourceIP === 'unknown') {
  return { json: { ...data, decision: 'monitor', shouldAutoExecute: false,
    executionReason: 'Skipped: internal/unknown IP', effectiveCount: 0 }};
}

// ── OVERRIDE 1: revoke_access → always investigate (human review) ────
if (aiAction === 'revoke_access') {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: true,
    executionReason: 'Insider threat — human review required', effectiveCount: 0 }};
}

// ── OVERRIDE 2: ransomware/malware/c2 → isolate_host always ─────────
if (threatType.includes('ransomware') || threatType.includes('malware') ||
    threatType.includes('c2') || threatType.includes('beacon')) {
  return { json: { ...data, decision: 'isolate_host', shouldAutoExecute: true,
    executionReason: `Critical: ${threatType} detected — isolating host`, effectiveCount: 99 }};
}

// ── COUNT-DRIVEN THRESHOLDS ──────────────────────────────────────────
// PRIMARY driver: 24h count — only goes UP, never drops
// This ensures the count always climbs toward the block threshold
const count24h     = parseInt(data.ip_history_count) || 0;
const velocity5m   = parseInt(data.ip_velocity_5m) || 0;
const lastDecision = data.ip_last_decision || 'none';

// Start with 24h count as base — this ONLY increases over time
let effectiveCount = count24h;

// Velocity is a BONUS only — catches burst attacks on top of count
// It adds urgency but never replaces the stable 24h count
if (velocity5m >= 10)      effectiveCount += 4;  // full brute force burst
else if (velocity5m >= 5)  effectiveCount += 2;  // moderate burst
else if (velocity5m >= 2)  effectiveCount += 1;  // minor burst

// Escalation bonuses — previous decisions matter
if (lastDecision === 'block_ip')         effectiveCount += 3;  // known bad actor
else if (lastDecision === 'investigate') effectiveCount += 2;  // warned, still hitting

// High severity rule bonus
if (ruleLevel >= 12) effectiveCount += 1;

let decision = 'monitor';
let shouldAutoExecute = false;
let executionReason = '';

if (effectiveCount >= 15) {
  decision = 'block_ip';
  shouldAutoExecute = true;
  executionReason = `Auto-block: effective count ${effectiveCount} >= 15 (24h: ${count24h}, 5min bonus: ${velocity5m}, last: ${lastDecision})`;

} else if (effectiveCount >= 7) {
  decision = 'investigate';
  shouldAutoExecute = true;
  executionReason = `Investigate: effective count ${effectiveCount} in 7-14 range — SOC team notified (24h: ${count24h}, 5min: ${velocity5m})`;

} else if (effectiveCount >= 4) {
  decision = 'monitor';
  shouldAutoExecute = false;
  executionReason = `Monitor: effective count ${effectiveCount} in 4-6 range (24h: ${count24h})`;

} else {
  decision = 'monitor';
  shouldAutoExecute = false;
  executionReason = `Log only: effective count ${effectiveCount} in 0-3 range — chill (24h: ${count24h})`;
}

return { json: { ...data, decision, shouldAutoExecute, executionReason, effectiveCount, count24h, velocity5m } };

