    if (parts.length !== 4 || parts.some(isNaN)) return false;
    const [a, b] = parts;
    return (
      a === 127 ||
      a === 10 ||
      (a === 172 && b >= 16 && b <= 31) ||
      (a === 192 && b === 168) ||
      (a === 100 && b >= 64 && b <= 127)
    );
  }
  const isLocalhost = isPrivateOrUnknown(sourceIP);

  item.json.sourceIP = sourceIP;
  item.json.isLocalhost = isLocalhost;
  item.json.shouldCheckVT = !isLocalhost;
}

