const d = $('AI Decision Engine').first().json;

const cleanTag = v => String(v || 'unknown')
  .replace(/[,= \t\n\r]/g, '_')
  .replace(/[^\x20-\x7E]/g, '')
  .substring(0, 64) || 'unknown';

const ts = Math.floor(Date.now() / 1000);

const line = [
  'telegram_sent',
  ',source_ip=' + cleanTag(d.sourceIP),
  ',decision=' + cleanTag(d.decision),
  ',agent=' + cleanTag(d.agent?.name || 'unknown'),
  ',threat_type=' + cleanTag(d.ai_threat_type),
  ' sent=1i',
  ' ' + ts
].join('');

// Pass through ALL original data so downstream nodes have full context
return [{
  json: {
    ...d,
    telegramSentLineProtocol: line
  }
}];

const body = $input.item.json.body || $input.item.json;

let severity = 'low';
const level = body.rule?.level || 0;

if (level >= 12) {
  severity = 'critical';
} else if (level >= 7) {
  severity = 'high';
} else if (level >= 4) {
  severity = 'medium';
}

const alert = {
  id: body.id || Date.now().toString(),
  timestamp: body.timestamp || new Date().toISOString(),
  rule: {
    description: body.rule?.description || 'Security alert detected',
    level: level,
    id: body.rule?.id || 'unknown'
  },
  agent: {
