return { json: { ...prevData, ip_velocity_5m: velocity5m } };

const responseBody = $input.item.json.body || $input.item.json.data || '';
const prevData = $('Parse 5min Velocity1').first().json;

let lastDecision = 'none';

try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const decisionIdx = headers.findIndex(h => h.trim() === 'decision');
    let latestDecision = 'none';
    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      const rowDecision = decisionIdx >= 0 ? (vals[decisionIdx] || '').trim() : '';
      if (rowDecision && rowDecision !== '' && rowDecision !== 'none') {
        if (latestDecision === 'none') latestDecision = rowDecision;
      }
    }
    lastDecision = latestDecision;
  }
} catch(e) { lastDecision = 'none'; }

return { json: { ...prevData, ip_last_decision: lastDecision } };

