const responseBody = $input.item.json.body || $input.item.json.data || '';
let alreadyBlocked = false;

try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const valueIdx = headers.findIndex(h => h.trim() === '_value');
    if (valueIdx >= 0) {
      const row = lines[1].split(',');
      const count = parseInt(row[valueIdx]) || 0;
      alreadyBlocked = count > 0;
    }
  }
} catch(e) {}

return [{ json: { ...$('AI Decision Engine').first().json, already_blocked: alreadyBlocked } }];

const data = $('AI Decision Engine').first().json;

const cleanTag = (v) => String(v || 'unknown').replace(/[,=\s"\\]+/g, '_').replace(/^_+|_+$/g, '').substring(0, 80) || 'unknown';
const cleanStr = (v) => String(v || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/[\n\r\t]/g, ' ').trim().substring(0, 150);
const num = (v, def=0) => { const n = parseFloat(v); return isNaN(n) ? def : n; };

const actionTaken = cleanTag(data.decision || 'monitor');
const sourceIP    = cleanTag(data.sourceIP || 'unknown');
const agentName   = cleanTag(data.agent?.name || 'unknown');
const mitreId     = cleanTag(data.ai_mitre_id || 'unknown');
const attackType  = cleanTag(data.ai_threat_type || 'unknown');
const severity    = cleanTag(data.severity || 'unknown');
const autoExec    = (data.shouldAutoExecute === true) ? 1 : 0;
const confidence  = parseFloat(data.ai_confidence) || 0;
const aiSeverity  = parseInt(data.ai_severity) || 0;
const ruleLevel   = parseInt(data.rule?.level) || 0;
const reason      = cleanStr(data.ai_reason || data.executionReason || '');

const alertLine = `decisions,host=wazuh,severity=${severity},agent=${agentName},attack_type=${attackType},decision=${actionTaken},source_ip=${sourceIP},mitre_id=${mitreId} rule_level=${ruleLevel},confidence=${confidence},ai_severity=${aiSeverity},auto_execute=${autoExec},reason="${reason}"`;

const shouldWriteBlockState = (actionTaken === 'block_ip');
let blockedLineProtocol = null;
if (shouldWriteBlockState) {
  blockedLineProtocol = `blocked_ips,source_ip=${sourceIP},agent=${agentName},attack_type=${attackType} blocked=1,rule_level=${ruleLevel},reason="${reason}"`;
}

return {
  json: {
    ...data,
    action_logged: true, action_taken: actionTaken,
    lineProtocol: alertLine,
    blockedLineProtocol,
    shouldWriteBlockState
  }
};

