  // 'http://<AGENT_IP_1>:9999',    // winpulkit — uncomment when ready
  // 'http://<AGENT_IP_2>:9999',      // lb110-006 — uncomment when ready
];

// Identify which host to isolate based on agent name
// Maps agent name to its Tailscale IP for targeting
const agentIPs = {
  'wazuh-lab': '172.19.0.1',
};

const targetIP = agentIPs[agentName] || null;

let isolateResults = [];

if (targetIP) {
  // Call the specific agent's blocker with isolate action
  try {
    const resp = await fetch(`http://${targetIP}:9999`, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ action: 'isolate', agent: agentName }),
      signal: AbortSignal.timeout(5000)
    });
    const result = await resp.json();
    isolateResults.push({ host: targetIP, result });
  } catch(e) {
    isolateResults.push({ host: targetIP, error: e.message });
