// Multi-agent IP block broadcast
// Calls all registered agent blockers simultaneously via Promise.allSettled
// Add new agents by uncommenting their line or adding a new entry

const agentBlockers = [
  'http://172.19.0.1:9999',           // wazuh-lab ✅ always active
  // 'http://100.115.14.31:9999',      // Windows LOQ — uncomment when deployed
  // 'http://<AGENT_IP_1>:9999',    // winpulkit — uncomment when deployed
  // 'http://<AGENT_IP_2>:9999',      // lb110-006 — uncomment when deployed
];

const ip = $('AI Decision Engine').first().json.sourceIP;

const results = await Promise.allSettled(
  agentBlockers.map(url =>
    fetch(url, {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ ip, action: 'block' }),
      signal: AbortSignal.timeout(5000)
    }).then(r => r.json()).catch(e => ({ error: e.message }))
  )
);

return [{
  json: {
    ...$('AI Decision Engine').first().json,
    block_results: results.map((r, i) => ({
      host: agentBlockers[i],
      result: r.status === 'fulfilled' ? r.value : { error: r.reason?.message }
    }))
  }
}];

const responseBody = $input.item.json.body || $input.item.json.data || '';
