// Build Ollama prompt — v12.9.10
// Runs BEFORE Ollama. Resolves all values in JS so the prompt contains real data.
const d = $input.item.json;

// At this stage data lives under d.alert.* — check that path FIRST
const alertDesc    = d.alert?.rule?.description || d.rule?.description || d.description || 'Security alert';
const ruleLevel    = d.alert?.rule?.level        || d.rule?.level        || 0;
const ruleId       = d.alert?.rule?.id           || d.rule?.id           || 'unknown';
const sourceIP     = d.sourceIP                  || 'unknown';
const agentName    = d.alert?.agent?.name        || d.agent?.name        || 'unknown';
const severity     = d.alert?.severity           || d.severity           || 'unknown';
const history24h   = d.ip_history_count          || 0;
const velocity5m   = d.ip_velocity_5m            || 0;
const lastDecision = d.ip_last_decision          || 'none';

// Extra context: only include lines that have actual values
const dstUser     = d.alert?.data?.dstuser       || '';
const srcUser     = d.alert?.data?.srcuser       || '';
const programName = d.alert?.data?.program_name  || '';
const dstIp       = d.alert?.data?.dstip         || '';
const protocol    = d.alert?.data?.protocol      || '';

const extraLines = [
  dstUser     ? `Target User: ${dstUser}`     : '',
  srcUser     ? `Source User: ${srcUser}`     : '',
  programName ? `Process: ${programName}`     : '',
  dstIp       ? `Destination IP: ${dstIp}`   : '',
  protocol    ? `Protocol: ${protocol}`       : '',
].filter(Boolean);

const userContent = [
  `Alert: ${alertDesc}`,
  `Rule Level: ${ruleLevel}/15`,
  `Rule ID: ${ruleId}`,
  `Source IP: ${sourceIP}`,
  `Agent: ${agentName}`,
  `Severity: ${severity}`,
  `Previous alerts 24h: ${history24h}`,
  `Velocity last 5min: ${velocity5m}`,
  `Last SOC decision for this IP: ${lastDecision}`,
  ...extraLines
].join('\n');

const ollamaPayload = {
  model: "hf.co/mradermacher/Foundation-Sec-8B-Instruct-GGUF:Q4_K_M",
  messages: [
    {
      role: "system",
      content: "You are a SOC Analyst API. Analyze the security alert and respond with JSON only.\n\nJSON fields:\n- threat_type: snake_case attack name (e.g. ssh_brute_force, port_scan, malware, ransomware, lateral_movement, data_exfiltration, privilege_escalation, c2_beacon, sql_injection, unknown)\n- severity: integer 1-10\n- mitre_id: MITRE ATT&CK ID (e.g. T1110, T1046, T1486)\n- confidence: float 0.0-1.0\n- action: exactly one of: block_ip, isolate_host, investigate, monitor, revoke_access\n- reason: one sentence explanation\n\nNo markdown, no backticks, no extra text. JSON only."
    },
    {
      role: "user",
      content: userContent
    }
  ],
  stream: false,
  options: { num_ctx: 4096, num_predict: 300, temperature: 0 }
};

return [{
  json: {
    ...d,
    ollamaPayload:   JSON.stringify(ollamaPayload),
    resolvedPrompt:  userContent
  }
}];

// Verify Block Result — v12.9.10
// Reads block_results from Block IP node.
// Determines ACTUAL outcome from blocker.py response.
// This is the block verification Sir requested — pipeline confirms iptables
// before sending any Telegram message.

const d      = $input.item.json;
const results = d.block_results || [];

let blocked        = false;   // freshly blocked this execution
let alreadyBlocked = false;   // was already in iptables
let failed         = false;
let errorMsg       = '';
let respondingHost = '';

for (const r of results) {
  if (r.result) {
    const status = r.result.status || '';
    if (status === 'blocked') {
      blocked = true;
      respondingHost = r.host;
    } else if (status === 'already_blocked') {
      alreadyBlocked = true;
      respondingHost = r.host;
    } else if (status === 'failed' || r.result.error) {
      failed = true;
      errorMsg = r.result.error || r.result.status || 'blocker returned failure';
    }
  } else if (r.error) {
    failed   = true;
    errorMsg = r.error;   // includes 'http_request_failed' if $http itself failed
  }
}

// Success = either fresh block OR already blocked (idempotent — iptables rule exists)
const blockSuccess  = blocked || alreadyBlocked;
const blockStatus   = blocked ? 'blocked' : alreadyBlocked ? 'already_blocked' : 'FAILED';
const blockIsFresh  = blocked && !alreadyBlocked;

return [{
  json: {
    ...d,
    block_success:       blockSuccess,
