    resolvedPrompt:  userContent
  }
}];

// Verify Block Result — reads direct httpRequest response from blocker.py
// blocker.py returns: {"status":"blocked"} or {"status":"already_blocked"} or {"status":"failed"}
const raw = $input.item.json;

// httpRequest with neverError=true returns body in different places depending on response
// Try all possible paths
let result = {};
try {
  if (typeof raw === 'object' && raw.status) {
    result = raw;
  } else if (raw.body && typeof raw.body === 'object') {
    result = raw.body;
  } else if (raw.body && typeof raw.body === 'string') {
    result = JSON.parse(raw.body);
  } else {
    result = raw;
  }
} catch(e) {
  result = { status: 'parse_error', error: e.message };
}

const status        = result.status || '';
const blocked       = status === 'blocked';
const alreadyBlocked= status === 'already_blocked';
const failed        = !blocked && !alreadyBlocked;
const blockSuccess  = blocked || alreadyBlocked;

return [{
  json: {
    ...$('AI Decision Engine').first().json,
    block_success:         blockSuccess,
    block_status:          blockSuccess ? status : 'FAILED',
    block_is_fresh:        blocked,
    block_already_existed: alreadyBlocked,
    block_error:           failed ? (result.error || result.status || 'blocker.py returned failure') : '',
    block_responding_host: 'http://172.19.0.1:9999',
    block_raw_response:    result
  }
}];

