const csvData = $input.item.json.data || $input.item.json.body || '';
let alerts = [];

try {
  const lines = csvData.split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length > 1) {
    const headers = lines[0].split(',');
    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      if (vals.length < 2) continue;
      const obj = {};
      headers.forEach((h, idx) => { obj[h.trim()] = vals[idx]?.trim() || ''; });
      if (obj._time || obj.description) {
        alerts.push({
          id: obj._time || Date.now().toString(),
          timestamp: obj._time || new Date().toISOString(),
          severity: obj.severity || 'low',
          description: obj.description || 'Security Alert',
          sourceIP: obj.source_ip || 'unknown',
          ai_confidence: parseFloat(obj.confidence) || 0,
          ai_action: obj.decision || 'monitor',
          decision: obj.decision || 'monitor',
          ai_reason: obj.reason || '',
          rule: { level: parseInt(obj.rule_level) || 0 },
          agent: { name: obj.agent || 'Unknown' }
        });
      }
    }
  }
} catch(e) { alerts = []; }

return { json: { alerts, count: alerts.length } };

// Write telegram_sent lock to InfluxDB BEFORE Telegram fires
