// Build Ollama prompt — v12.9.10
// Runs BEFORE Ollama. Resolves all values in JS so the prompt contains real data.
const d = $input.item.json;

// At this stage data lives under d.alert.* — check that path FIRST
const alertDesc    = d.alert?.rule?.description || d.rule?.description || d.description || 'Security alert';
const ruleLevel    = d.alert?.rule?.level        || d.rule?.level        || 0;
const ruleId       = d.alert?.rule?.id           || d.rule?.id           || 'unknown';
const sourceIP     = d.sourceIP                  || 'unknown';
const agentName    = d.alert?.agent?.name        || d.agent?.name        || 'unknown';
const severity     = d.alert?.severity           || d.severity           || 'unknown';
const history24h   = d.ip_history_count          || 0;
const velocity5m   = d.ip_velocity_5m            || 0;
const lastDecision = d.ip_last_decision          || 'none';

// Extra context: only include lines that have actual values
const dstUser     = d.alert?.data?.dstuser       || '';
const srcUser     = d.alert?.data?.srcuser       || '';
const programName = d.alert?.data?.program_name  || '';
const dstIp       = d.alert?.data?.dstip         || '';
const protocol    = d.alert?.data?.protocol      || '';

const extraLines = [
  dstUser     ? `Target User: ${dstUser}`     : '',
  srcUser     ? `Source User: ${srcUser}`     : '',
  programName ? `Process: ${programName}`     : '',
  dstIp       ? `Destination IP: ${dstIp}`   : '',
  protocol    ? `Protocol: ${protocol}`       : '',
].filter(Boolean);

const userContent = [
  `Alert: ${alertDesc}`,
  `Rule Level: ${ruleLevel}/15`,
  `Rule ID: ${ruleId}`,
  `Source IP: ${sourceIP}`,
  `Agent: ${agentName}`,
  `Severity: ${severity}`,
  `Previous alerts 24h: ${history24h}`,
  `Velocity last 5min: ${velocity5m}`,
  `Last SOC decision for this IP: ${lastDecision}`,
  ...extraLines
].join('\n');

const ollamaPayload = {
  model: "hf.co/mradermacher/Foundation-Sec-8B-Instruct-GGUF:Q4_K_M",
  messages: [
    {
      role: "system",
      content: "You are a SOC Analyst API for an enterprise network. Analyze the security alert and respond with JSON only.\n\nBefore classifying, reason through these questions:\n\n1. How many times has this IP appeared in the last 24 hours?\n   - 0 to 2 times: isolated event, low confidence, do not escalate\n   - 3 to 9 times: pattern emerging, moderate confidence\n   - 10 or more: repeated behavior, high confidence\n\n2. What is the velocity in last 5 minutes?\n   - 0 to 2: could be human error or normal failure\n   - 3 to 9: suspicious, elevated\n   - 10 or more: automated, very high confidence\n\n3. What was the last SOC decision for this IP?\n   - none: first time seen, be cautious\n   - monitor: re-appearing IP, raise severity slightly\n   - investigate: already suspicious, escalate\n   - block_ip: was blocked before, treat seriously\n\n4. Confidence must reflect the evidence you have:\n   - First alert, count 0-2: confidence maximum 0.5\n   - Count 3-9: confidence 0.5 to 0.75\n   - Count 10+: confidence 0.75 to 0.95\n\n5. ACTION must follow this strict rule based on count and velocity:\n   - count 0 to 2 AND velocity 0 to 2: action must be monitor\n   - count 3 to 9 OR velocity 3 to 9: action must be investigate\n   - count 10 or more OR velocity 10 or more: action must be block_ip\n\n6. CRITICAL OVERRIDE FOR MALWARE:\n   - If the alert describes process injection, malware, rootkits, or critical host compromise, ACTION MUST BE isolate_host immediately, even if count is 1. Do not monitor or investigate a compromised host.\n\n7. threat_type must reflect the COUNT not just the alert text:\n   - count 0 to 2: use a conservative label\n   - count 3 to 9: use a pattern label\n   - count 10 or more: use a confirmed label\n\n8. Reason field must reflect the actual numbers you received, not generic statements.\n\nRESPOND WITH THIS JSON STRUCTURE ONLY — no markdown, no backticks, no extra text:\n{\"threat_type\": \"snake_case name\", \"severity\": integer 1-10, \"mitre_id\": \"T-code\", \"confidence\": float 0.0-1.0, \"action\": \"monitor or investigate or block_ip or isolate_host or revoke_access\", \"reason\": \"two sentences based on actual numbers\"}"
    },
    {
      role: "user",
      content: userContent
    }
  ],
  stream: false,
  options: { num_ctx: 4096, num_predict: 300, temperature: 0 }
};

return [{
  json: {
    ...d,
    ollamaPayload:   ollamaPayload,   // object, not string — HTTP node serializes it
    resolvedPrompt:  userContent
  }
}];

// Verify Block Result — v12.9.10 final
// n8n httpRequest returns blocker.py response wrapped in: { data: '{"status":"blocked",...}' }
// So we parse $input.item.json.data first, then read .status

const raw = $input.item.json;

let result = {};
try {
  if (raw.data && typeof raw.data === 'string') {
    result = JSON.parse(raw.data);          // main path: data is a JSON string
  } else if (raw.data && typeof raw.data === 'object') {
    result = raw.data;                      // fallback: data is already an object
  } else if (raw.status) {
    result = raw;                           // fallback: status at top level
  }
} catch(e) {
  result = { status: 'parse_error', error: e.message };
}

const status         = result.status || '';
const blocked        = status === 'blocked';
const alreadyBlocked = status === 'already_blocked';
const blockSuccess   = blocked || alreadyBlocked;

return [{
  json: {
    ...$('AI Decision Engine').first().json,
    block_success:         blockSuccess,
    block_status:          blockSuccess ? status : 'FAILED',
    block_is_fresh:        blocked,
    block_already_existed: alreadyBlocked,
    block_error:           blockSuccess ? '' : (result.error || status || 'no response from blocker.py'),
    block_responding_host: 'http://172.19.0.1:9999',
    block_raw_response:    result
  }
}];

