const body = $input.item.json.body || $input.item.json;

let severity = 'low';
const level = body.rule?.level || 0;
if (level >= 12)      severity = 'critical';
else if (level >= 7)  severity = 'high';
else if (level >= 4)  severity = 'medium';

const alert = {
  id:        body.id || Date.now().toString(),
  timestamp: body.timestamp || new Date().toISOString(),
  rule: {
    description: body.rule?.description || 'Security alert detected',
    level:       level,
    id:          body.rule?.id || 'unknown'
  },
  agent: {
    name: body.agent?.name || 'Unknown Agent',
    id:   body.agent?.id   || 'unknown'
  },
  data: {
    ...(body.data || {}),
    srcip:        body.data?.srcip        || '',
    dstip:        body.data?.dstip        || '',
    // Windows AD/auth target user
    dstuser:      body.data?.dstuser
                  || body.data?.win?.eventdata?.targetUserName
                  || body.data?.win?.eventdata?.TargetUserName
                  || '',
    // Source user (lateral movement / privilege escalation context)
    srcuser:      body.data?.srcuser
                  || body.data?.win?.eventdata?.subjectUserName
                  || body.data?.win?.eventdata?.SubjectUserName
                  || '',
    // Process context (malware, ransomware, C2 often visible here)
    program_name: body.data?.program_name
                  || body.data?.win?.eventdata?.image
                  || body.data?.win?.eventdata?.Image
                  || body.data?.win?.eventdata?.processName
                  || '',
    protocol:     body.data?.protocol || '',
    action:       body.data?.action   || '',
  },
  full_log:    body.full_log || '',
  severity:    severity,
  description: body.rule?.description || 'Security alert detected'
};


// Extract syscheck (FIM) data if present
const syscheck = {
  path:      body.syscheck?.path      || body.data?.path      || '',
  event:     body.syscheck?.event     || '',
  sha1_after: body.syscheck?.sha1_after || '',
