    const match = alert.full_log.match(ipRegex);
    if (match) sourceIP = match[1];
  }

  function isPrivateOrUnknown(ip) {
    if (!ip || ip === 'unknown') return true;
    const parts = ip.split('.').map(Number);
    if (parts.length !== 4 || parts.some(isNaN)) return true;
    const [a, b] = parts;
    return (
      a === 127 ||
      a === 10 ||
      (a === 172 && b >= 16 && b <= 31) ||
      (a === 192 && b === 168)
      // NOTE: 100.64.0.0/10 (Tailscale) intentionally ALLOWED
      // Insider threats from compromised Tailscale peers must be processed
    );
