const threatType = (data.ai_threat_type || '').toLowerCase();
const aiOffline  = data.ai_offline  === true;

// ── MITRE map — rule ID → guaranteed accurate MITRE ID ─────────────────────
// Overrides AI MITRE output. AI gets MITRE wrong ~14% of the time.
// Wazuh rule IDs are ground truth — this map is deterministic.
const MITRE_MAP = {
  '5716': 'T1110',    // SSH authentication failure
  '5710': 'T1021',    // Lateral movement
  '5715': 'T1078',    // Successful login after failures
  '1001': 'T1082',    // System information enumeration
  '1002': 'T1046',    // Port scan
  '5402': 'T1548',    // Unauthorized sudo / privilege escalation
  '5403': 'T1548',    // Sudo rules changed
  '5501': 'T1136',    // User account created
  '5502': 'T1531',    // User account deleted
  '87002': 'T1078',   // Insider threat / sensitive access
  '87105': 'T1055',   // Process injection
  '87106': 'T1055',   // Process injection variant
  '87110': 'T1071',   // C2 communication
  '510':   'T1014',   // Rootkit detection
  '511':   'T1014',   // Rootkit detection
  '533':   'T1014',   // Rootkit detection
  '5903': 'T1059',    // Suspicious process execution
  '5904': 'T1059',    // Suspicious process execution
  '31103': 'T1190',   // SQL injection
  '31104': 'T1190',   // SQL injection variant
  '62300': 'T1486',   // Ransomware / mass encryption
  '62301': 'T1486',   // Ransomware variant
  '62302': 'T1486',   // Ransomware variant
  '100200': 'T1059',  // Custom malware
  '100201': 'T1059',  // Custom malware
  '100202': 'T1059',  // Custom malware
};

// Use mapped MITRE if available, otherwise trust AI
const finalMitreId = MITRE_MAP[ruleId] || data.ai_mitre_id || 'unknown';

// ── Skip internal/unknown IPs ──────────────────────────────────────────────
if (data.isLocalhost || sourceIP === 'unknown') {
  return { json: { ...data, decision: 'monitor', shouldAutoExecute: false,
    ai_mitre_id: finalMitreId,
    executionReason: 'Skipped: internal/unknown IP', effectiveCount: 0 }};
}

