    executionReason:  `Force isolate: Wazuh rule ${ruleId} matched host-compromise criteria`,
    effectiveCount:   99
  }};
}

// ── INVESTIGATE override: rules that always need analyst review ────────────
const INVESTIGATE_RULE_IDS = [
  '5715',   // Successful login after multiple failures
  '5503',   // User added to group
  '5501',   // New user created
];

const forceInvestigate = INVESTIGATE_RULE_IDS.includes(ruleId);

if (forceInvestigate) {
  return { json: { ...data,
    decision:          'investigate',
    shouldAutoExecute: true,
    ai_mitre_id:       finalMitreId,
    executionReason:   `Force investigate: Wazuh rule ${ruleId} — requires analyst review`,
    effectiveCount:    7
  }};
