        </div>
        <div class="alerts-container">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">
                <h2 style="color:white">Recent Security Alerts + AI Decisions</h2>
                <button class="refresh-btn" onclick="loadAlerts()">\uD83D\uDD04 Refresh</button>
            </div>
