    <script>
        function loadAlerts() {
            fetch('/webhook/get-alerts')
                .then(r => r.json())
                .then(data => { displayAlerts(data.alerts || []); updateStats(data.alerts || []); })
                .catch(() => { document.getElementById('alerts-list').innerHTML = '<div class="no-alerts">Error loading alerts.</div>'; });
        }
        function displayAlerts(alerts) {
            const c = document.getElementById('alerts-list');
            if (!alerts.length) { c.innerHTML = '<div class="no-alerts">No alerts yet. Waiting for Wazuh events...</div>'; return; }
            c.innerHTML = alerts.map(a => {
                const action = a.ai_action || a.decision || 'monitor';
                return '<div class="alert ' + a.severity + '">' +
                    '<div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:12px;"><div class="alert-title">' + (a.description || 'Security Alert') + '<span class="action-badge ' + action + '">\u26A1 ' + action.replace(/_/g,' ') + '</span></div>' +
                    '<span class="severity-badge ' + a.severity + '">' + a.severity + '</span></div>' +
                    '<div class="alert-meta"><span>\uD83D\uDD50 ' + formatTime(a.timestamp) + '</span><span>\uD83D\uDDA5\uFE0F ' + (a.agent?.name || 'Unknown') + '</span><span>\uD83D\uDCCA Level: ' + (a.rule?.level || 'N/A') + '</span><span>\uD83C\uDF10 IP: ' + (a.sourceIP || 'N/A') + '</span><span>\uD83C\uDFAF Confidence: ' + Math.round((a.ai_confidence || 0) * 100) + '%</span></div>' +
                    (a.ai_reason ? '<div class="ai-analysis"><span style="color:#c084fc;font-weight:600;">\uD83E\uDD16 AI:</span> ' + a.ai_reason + '</div>' : '') +
                '</div>';
            }).join('');
        }
        function updateStats(alerts) {
            document.getElementById('total-alerts').textContent = alerts.length;
            document.getElementById('critical-count').textContent = alerts.filter(a => a.severity === 'critical').length;
            document.getElementById('high-count').textContent = alerts.filter(a => a.severity === 'high').length;
            document.getElementById('blocked-count').textContent = alerts.filter(a => a.decision === 'block_ip').length;
            document.getElementById('last-update').textContent = new Date().toLocaleTimeString();
        }
        function formatTime(t) {
            const d = new Date(t), n = new Date(), diff = Math.floor((n-d)/60000);
            if (diff < 1) return 'Just now'; if (diff < 60) return diff + 'm ago';
            if (diff < 1440) return Math.floor(diff/60) + 'h ago'; return d.toLocaleString();
        }
        loadAlerts();
        setInterval(loadAlerts, 5000);
    </script>
</body>
</html>`;
return { json: { html } };

const csvData = $input.item.json.data || $input.item.json.body || '';
let alerts = [];

try {
  const lines = csvData.split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length > 1) {
    const headers = lines[0].split(',');
    for (let i = 1; i < lines.length; i++) {
      const vals = lines[i].split(',');
      if (vals.length < 2) continue;
      const obj = {};
      headers.forEach((h, idx) => { obj[h.trim()] = vals[idx]?.trim() || ''; });
      if (obj._time || obj.description) {
        alerts.push({
          id: obj._time || Date.now().toString(),
          timestamp: obj._time || new Date().toISOString(),
          severity: obj.severity || 'low',
          description: obj.description || 'Security Alert',
          sourceIP: obj.source_ip || 'unknown',
          ai_confidence: parseFloat(obj.confidence) || 0,
          ai_action: obj.decision || 'monitor',
          decision: obj.decision || 'monitor',
          ai_reason: obj.reason || '',
          rule: { level: parseInt(obj.rule_level) || 0 },
          agent: { name: obj.agent || 'Unknown' }
        });
      }
    }
  }
} catch(e) { alerts = []; }

return { json: { alerts, count: alerts.length } };

// Write telegram_sent lock to InfluxDB BEFORE Telegram fires
// This prevents duplicate Telegram messages in concurrent executions
// Also passes through all original AI Decision Engine data unchanged

const d = $('AI Decision Engine').first().json;

const cleanTag = v => String(v || 'unknown')
  .replace(/[,= \t\n\r]/g, '_')
  .replace(/[^\x20-\x7E]/g, '')
  .substring(0, 64) || 'unknown';

const ts = Math.floor(Date.now() / 1000);

const line = [
  'telegram_sent',
  ',source_ip=' + cleanTag(d.sourceIP),
  ',decision=' + cleanTag(d.decision),
  ',agent=' + cleanTag(d.agent?.name || 'unknown'),
  ',threat_type=' + cleanTag(d.ai_threat_type),
  ' sent=1i',
  ' ' + ts
].join('');

// Pass through ALL original data so downstream nodes have full context
return [{
  json: {
    ...d,
    telegramSentLineProtocol: line
  }
}];

// ISOLATE_HOST Action
// Uses $http (n8n built-in) instead of fetch — fetch is not available in n8n Code nodes
const d = $('AI Decision Engine').first().json;
const agentName = d.agent?.name || 'unknown';
const sourceIP  = d.sourceIP || 'unknown';

const agentIPs = {
  'wazuh-lab':  '172.19.0.1',
  // 'winpulkit':  '<AGENT_IP_1>',
  // 'lb110-006':  '<AGENT_IP_2>',
};

const targetIP = agentIPs[agentName] || null;
let isolateResults = [];

if (targetIP) {
  try {
    const response = await $http.request({
      method: 'POST',
      url: `http://${targetIP}:9999`,
      headers: { 'Content-Type': 'application/json' },
      body: { action: 'isolate', agent: agentName, ip: sourceIP },
      json: true
    });
    isolateResults.push({ host: targetIP, result: response });
  } catch(e) {
    isolateResults.push({ host: targetIP, error: e.message });
  }
} else {
  isolateResults.push({ host: 'unknown', error: `No IP mapping for agent: ${agentName}` });
}

return [{ json: {
  ...d,
  isolate_results: isolateResults,
  isolation_target_agent: agentName,
  isolation_target_ip: targetIP,
  isolation_triggered_by: sourceIP,
  isolation_timestamp: new Date().toISOString()
}}];

const d = $input.item.json;
