return { json: { ...d, lineProtocol } };

const responseBody = $input.item.json.body || $input.item.json.data || '';
let recentCount = 0;

try {
  const lines = String(responseBody).split('\n').filter(l => l.trim() && !l.startsWith('#'));
  if (lines.length >= 2) {
    const headers = lines[0].split(',');
    const valueIdx = headers.findIndex(h => h.trim() === '_value');
    if (valueIdx >= 0) {
      for (let i = 1; i < lines.length; i++) {
        const vals = lines[i].split(',');
        if (vals[valueIdx]) recentCount += parseInt(vals[valueIdx]) || 0;
      }
    }
  }
} catch(e) { recentCount = 0; }

// Threshold is now > 0 (not > 1) because we query actual sent messages not processed alerts
// If ANY telegram was sent for this IP+decision in the last 300s, suppress
const suppressDuplicate = recentCount > 0;
const dec = $('AI Decision Engine').first().json.decision;

return {
  json: {
    ...$('AI Decision Engine').first().json,
    suppress_duplicate: suppressDuplicate,
    recent_telegram_sent_count: recentCount,
    tg_dedup_note: suppressDuplicate
      ? `Telegram already sent for ${dec} on this IP in last 300s (sent_count: ${recentCount}) — suppressing`
      : `No recent Telegram sent for this IP+decision — proceeding`
  }
};

