// ── MITRE map — rule ID → guaranteed accurate MITRE ID 
const MITRE_MAP = {
  '5716': 'T1110', '5710': 'T1021', '5715': 'T1078', '1001': 'T1082', '1002': 'T1046',
  '5402': 'T1548', '5403': 'T1548', '5501': 'T1136', '5502': 'T1531', '87002': 'T1078',
  '87105': 'T1055', '87106': 'T1055', '87110': 'T1071', '510': 'T1014', '511': 'T1014',
  '533': 'T1014', '5903': 'T1059', '5904': 'T1059', '31103': 'T1190', '31104': 'T1190',
  '62300': 'T1486', '62301': 'T1486', '62302': 'T1486', '100200': 'T1059', '100201': 'T1059',
  '100202': 'T1059', '100020': 'T1486', '100021': 'T1486',
};
const finalMitreId = MITRE_MAP[ruleId] || data.ai_mitre_id || 'unknown';

if (aiAction === 'isolate_host') {
  const agentName = data.agent?.name || '';
  if (agentName === 'wazuh-lab') {
    return [{ json: { ...data, decision: 'investigate', shouldAutoExecute: true,
      executionReason: 'Isolation skipped: SOC server protected — escalated to investigate' }}];
  }
  return [{ json: { ...data, decision: 'isolate_host', shouldAutoExecute: true,
    executionReason: 'AI classified as ransomware/host compromise' }}];
}

// ── isLocalhost → always monitor (no action on internal-only traffic)
if (data.isLocalhost) {
  return { json: { ...data, decision: 'monitor', shouldAutoExecute: false, ai_mitre_id: finalMitreId, executionReason: 'Skipped: internal IP', effectiveCount: 0 }};
}

// ── Force-isolate list — checked BEFORE unknown-IP shortcut so FIM ransomware alerts are never downgraded
const ISOLATE_RULE_IDS = [
  '510', '511', '533', '5903', '5904',
  '62300', '62301', '62302',
  '87105', '87106', '87110',
  '100200', '100201', '100202',
  '100020', '100021'   // ← Atomic Red Team ransomware rules
];
const ISOLATE_DESC_KEYWORDS = [
  'ransomware', 'cobalt strike', 'cobaltstrike', 'rootkit', 'trojan',
  'backdoor', 'lateral movement', 'mimikatz', 'credential dump',
  'process injection', 'process hollowing'
];

const keywordMatch = ISOLATE_DESC_KEYWORDS.some(k => ruleDesc.includes(k));
const forceIsolate = ISOLATE_RULE_IDS.includes(ruleId) || (keywordMatch && ruleLevel >= 10);

if (forceIsolate) {
  const agentName = data.agent?.name || '';
  if (agentName === 'wazuh-lab') {
    return { json: { ...data, decision: 'investigate', shouldAutoExecute: true,
      ai_mitre_id: finalMitreId, executionReason: 'Isolation skipped: SOC server protected — escalated to investigate' }};
  }
  return { json: { ...data, decision: 'isolate_host', shouldAutoExecute: true,
    ai_threat_type: 'malware', ai_mitre_id: finalMitreId, ai_action: 'isolate_host',
    ai_reason: `Host compromise detected — immediate isolation required`,
    executionReason: `Force isolate: Wazuh rule ${ruleId} or high-level keyword matched`,
    effectiveCount: 99 }};
}

// ── Unknown IP shortcut (only reached if NOT a force-isolate rule)
if (sourceIP === 'unknown') {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: true, ai_mitre_id: finalMitreId, executionReason: 'Unknown IP detected — Manual investigation required', effectiveCount: 7 }};
}

if (aiAction === 'revoke_access') {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: true, ai_mitre_id: finalMitreId, executionReason: 'Insider threat — human review required', effectiveCount: 0 }};
}

// ── Investigate overrides
const INVESTIGATE_RULE_IDS = ['5715', '5503', '5501'];
if (INVESTIGATE_RULE_IDS.includes(ruleId)) {
  return { json: { ...data, decision: 'investigate', shouldAutoExecute: true, ai_mitre_id: finalMitreId, executionReason: `Force investigate: Wazuh rule ${ruleId}`, effectiveCount: 7 }};
}

// ── Ollama threat-type isolate
const isC2 = threatType === 'c2_beacon' || threatType === 'c2_communication' || threatType === 'c2' || threatType.startsWith('c2_');
if (threatType.includes('ransomware') || threatType.includes('malware') || isC2 || threatType.includes('beacon')) {
  return { json: { ...data, decision: 'isolate_host', shouldAutoExecute: true, ai_mitre_id: finalMitreId, executionReason: `Critical: ${threatType} detected — isolating host`, effectiveCount: 99 }};
