// ── Standard effectiveCount escalation
const count24h    = parseInt(data.ip_history_count) || 0;
const velocity5m  = parseInt(data.ip_velocity_5m)   || 0;
const lastDecision = data.ip_last_decision || 'none';
let effectiveCount = count24h;

if (velocity5m >= 10) effectiveCount += 4; else if (velocity5m >= 5) effectiveCount += 2; else if (velocity5m >= 2) effectiveCount += 1;
if (lastDecision === 'block_ip') effectiveCount += 3; else if (lastDecision === 'investigate') effectiveCount += 2;
if (ruleLevel >= 12) effectiveCount += 1;

let decision = 'monitor', shouldAutoExecute = false, executionReason = '';
if (effectiveCount >= 15) { decision = 'block_ip';     shouldAutoExecute = true;  executionReason = `Auto-block: effective count ${effectiveCount}`; }
else if (effectiveCount >= 7)  { decision = 'investigate'; shouldAutoExecute = true;  executionReason = `Investigate: effective count ${effectiveCount}`; }
else if (effectiveCount >= 4)  { decision = 'monitor';     shouldAutoExecute = true;  executionReason = `Monitor: effective count ${effectiveCount}`; }
else                           { decision = 'monitor';     shouldAutoExecute = false; executionReason = `Log only: effective count ${effectiveCount}`; }

if (aiOffline) executionReason = '[AI OFFLINE — fallback mode] ' + executionReason;

return { json: { ...data, decision, shouldAutoExecute, executionReason, effectiveCount, count24h, velocity5m, ai_mitre_id: finalMitreId } };

