// Build Ollama prompt — v12.9.11
const d = $input.item.json;

const alertDesc    = d.alert?.rule?.description || d.rule?.description || d.description || 'Security alert';
const ruleLevel    = d.alert?.rule?.level        || d.rule?.level        || 0;
const ruleId       = d.alert?.rule?.id           || d.rule?.id           || 'unknown';
const sourceIP     = d.sourceIP                  || 'unknown';
const agentName    = d.alert?.agent?.name        || d.agent?.name        || 'unknown';
const severity     = d.alert?.severity           || d.severity           || 'unknown';
const history24h   = d.ip_history_count          || 0;
const velocity5m   = d.ip_velocity_5m            || 0;
const lastDecision = d.ip_last_decision          || 'none';

const mitreIds     = d.alert?.rule?.mitre?.id    || d.rule?.mitre?.id    || [];
const ruleGroups   = d.alert?.rule?.groups       || d.rule?.groups       || [];
const filePath     = d.alert?.syscheck?.path     || d.syscheck?.path     || '';

const dstUser     = d.alert?.data?.dstuser       || '';
const srcUser     = d.alert?.data?.srcuser       || '';
const programName = d.alert?.data?.program_name  || '';
const dstIp       = d.alert?.data?.dstip         || '';
const protocol    = d.alert?.data?.protocol      || '';

const extraLines = [
  dstUser     ? `Target User: ${dstUser}`       : '',
  srcUser     ? `Source User: ${srcUser}`       : '',
  programName ? `Process: ${programName}`       : '',
  dstIp       ? `Destination IP: ${dstIp}`     : '',
  protocol    ? `Protocol: ${protocol}`         : '',
  filePath    ? `Affected File: ${filePath}`    : '',
  mitreIds.length ? `MITRE ATT&CK: ${mitreIds.join(', ')}` : '',
  ruleGroups.length ? `Alert Groups: ${ruleGroups.join(', ')}` : '',
].filter(Boolean);

const userContent = [
  `Alert: ${alertDesc}`,
  `Rule Level: ${ruleLevel}/15`,
  `Rule ID: ${ruleId}`,
  `Source IP: ${sourceIP}`,
  `Agent (Host): ${agentName}`,
  `Severity: ${severity}`,
  `Previous alerts from this IP in 24h: ${history24h}`,
  `Alert velocity last 5min: ${velocity5m}`,
  `Last SOC decision for this IP: ${lastDecision}`,
  ...extraLines
].join('\n');

const systemPrompt = `You are a SOC Analyst API for an enterprise network protecting 100-500 employees. Analyze security alerts and respond with JSON only.

You handle TWO fundamentally different threat classes. Identify which class this alert belongs to FIRST:

CLASS A — NETWORK THREATS (brute force, port scans, login failures):
These have a source IP, occur over the network, and scale with repetition.
Reasoning for Class A:
1. Count last 24h: 0-2 = isolated, 3-9 = pattern, 10+ = confirmed
2. Velocity last 5min: 0-2 = human, 3-9 = suspicious, 10+ = automated
3. Last decision: none = cautious, monitor = raise, investigate = escalate, block_ip = serious
4. Action rules:
   - count 0-2 AND velocity 0-2: monitor
   - count 3-9 OR velocity 3-9: investigate
   - count 10+ OR velocity 10+: block_ip
5. Confidence scales with count: 0-2 = max 0.5, 3-9 = 0.5-0.75, 10+ = 0.75-0.95

CLASS B — HOST COMPROMISE THREATS (ransomware, malware, rootkits, FIM anomalies):
These target the host filesystem or processes directly. Source IP is irrelevant — the damage is already on the machine. Count and velocity of IP history do NOT apply.
Indicators of Class B:
- MITRE techniques: T1486 (ransomware), T1055 (injection), T1014 (rootkit), T1485 (destruction), T1059 (execution), T1036 (masquerading)
- Alert groups containing: ransomware, malware, rootkit, fim
- Rule level 12 or above with file integrity monitoring context
- Source IP is unknown or localhost
- Alert describes file encryption, mass deletion, or process injection

Reasoning for Class B:
1. Is the host already compromised or actively being compromised? Yes = isolate_host immediately.
2. Ransomware encrypting files = host must be isolated before it spreads. Do not wait for IP thresholds.
3. Unknown source IP in a host compromise context means the attacker is already inside — blocking an IP does nothing.
4. isolate_host is the ONLY valid response to active ransomware, malware execution, or rootkit detection.
5. block_ip is INVALID for Class B — there is no IP to block that would stop the damage.

RESPONSE RULES:
- If Class B indicators present: action MUST be isolate_host, confidence 0.85-0.95
- Never return block_ip for a ransomware or FIM-based alert
- Never return monitor for a level 12 alert with ransomware indicators
- Reason must explain which class you identified and why

RESPOND WITH THIS JSON STRUCTURE ONLY — no markdown, no backticks, no extra text:
{"threat_type": "snake_case_name", "severity": integer 1-10, "mitre_id": "T-code", "confidence": float 0.0-1.0, "action": "monitor or investigate or block_ip or isolate_host or revoke_access", "reason": "two sentences identifying threat class and justifying action"}`;

const ollamaPayload = {
  model: "hf.co/mradermacher/Foundation-Sec-8B-Instruct-GGUF:Q4_K_M",
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user",   content: userContent  }
  ],
  stream: false,
  options: { num_ctx: 4096, num_predict: 300, temperature: 0 }
};

return [{
  json: {
    ...d,
    ollamaPayload:  ollamaPayload,
    resolvedPrompt: userContent
  }
}];

// Verify Block Result — v12.9.10 final
// n8n httpRequest returns blocker.py response wrapped in: { data: '{"status":"blocked",...}' }
// So we parse $input.item.json.data first, then read .status

const raw = $input.item.json;

let result = {};
try {
  if (raw.data && typeof raw.data === 'string') {
    result = JSON.parse(raw.data);          // main path: data is a JSON string
  } else if (raw.data && typeof raw.data === 'object') {
    result = raw.data;                      // fallback: data is already an object
  } else if (raw.status) {
    result = raw;                           // fallback: status at top level
  }
} catch(e) {
  result = { status: 'parse_error', error: e.message };
}

const status         = result.status || '';
const blocked        = status === 'blocked';
const alreadyBlocked = status === 'already_blocked';
const blockSuccess   = blocked || alreadyBlocked;

return [{
  json: {
    ...$('AI Decision Engine').first().json,
    block_success:         blockSuccess,
    block_status:          blockSuccess ? status : 'FAILED',
    block_is_fresh:        blocked,
    block_already_existed: alreadyBlocked,
    block_error:           blockSuccess ? '' : (result.error || status || 'no response from blocker.py'),
    block_responding_host: 'http://172.19.0.1:9999',
    block_raw_response:    result
  }
}];

